// Uma requisição típica passando pela arquitetura:
// Cliente -> API Gateway -> Pedidos Service -> (evento) -> Estoque Service
//                                             -> (evento) -> Pagamentos Service

// Cada serviço só enxerga o PRÓPRIO banco — não existe JOIN entre eles.
// Pedidos Service consultando o "nome do cliente" que mora no Auth Service
// precisa fazer uma chamada (síncrona ou via evento), nunca um JOIN direto:

@Service
public class PedidoService {
    private final RestClient authServiceClient; // chamada HTTP pro outro serviço

    public PedidoDetalhado buscarComCliente(Long pedidoId) {
        Pedido pedido = pedidoRepository.findById(pedidoId).orElseThrow();
        ClienteDTO cliente = authServiceClient.get()
            .uri("/clientes/{id}", pedido.getClienteId())
            .retrieve()
            .body(ClienteDTO.class); // chamada de rede — pode falhar, pode ser lenta
        return new PedidoDetalhado(pedido, cliente);
    }
}

@Service
public class PagamentoClient {

    private final RestClient restClient;

    public PagamentoClient(RestClient restClient) {
        this.restClient = restClient;
    }

    @CircuitBreaker(name = "pagamentoService", fallbackMethod = "fallbackPagamento")
    @Retry(name = "pagamentoService")
    @TimeLimiter(name = "pagamentoService")
    public StatusPagamento consultar(String pedidoId) {
        return restClient.get()
            .uri("/pagamentos/{id}/status", pedidoId)
            .retrieve()
            .body(StatusPagamento.class);
    }

    // Se o serviço de pagamentos cair, o circuito abre e isso é chamado
    // IMEDIATAMENTE, sem nem tentar a chamada de rede — não derruba o
    // serviço de pedidos junto
    private StatusPagamento fallbackPagamento(String pedidoId, Exception ex) {
        return StatusPagamento.INDISPONIVEL;
    }
}

