// Sem circuit breaker: cada chamada tenta de verdade, mesmo sabendo
// (pelas últimas 50 tentativas) que o serviço está fora do ar
@Service
public class PagamentoClientSemProtecao {

    public StatusPagamento consultar(String pedidoId) {
        // se pagamentoService está caído, isso trava por até o timeout padrão
        // (às vezes 30s+) — em alto tráfego, isso esgota o pool de threads/conexões
        // do PRÓPRIO serviço de pedidos, derrubando ele também
        return restClient.get()
            .uri("/pagamentos/{id}/status", pedidoId)
            .retrieve()
            .body(StatusPagamento.class);
    }
}
// Isso é o "efeito dominó": um serviço fora do ar derruba os que dependem dele.

