// Saga coreografada via eventos — cada serviço reage e publica o próximo evento

@Service
public class PedidoSagaListener {

    @EventListener
    public void aoReceberEstoqueReservado(EstoqueReservadoEvent evento) {
        // passo seguinte: tentar cobrar o pagamento
        eventPublisher.publish(new CobrarPagamentoCommand(evento.pedidoId()));
    }

    @EventListener
    public void aoReceberPagamentoFalhou(PagamentoFalhouEvent evento) {
        // AÇÃO DE COMPENSAÇÃO: desfaz o passo anterior (reserva de estoque)
        // — não existe rollback automático entre serviços, isso é código explícito
        eventPublisher.publish(new CancelarReservaEstoqueCommand(evento.pedidoId()));
    }
}

