// Tentativa (errada) de replicar uma transação ACID entre serviços:
// isso NÃO existe em arquitetura de microservices
@Transactional // <- essa anotação só controla UMA conexão/transação de banco,
public void processarPedidoCompleto(Pedido pedido) {
    estoqueService.reservar(pedido);      // chamada de rede pra OUTRO serviço
    pagamentoService.cobrar(pedido);       // chamada de rede pra OUTRO serviço
    notificacaoService.confirmar(pedido);  // chamada de rede pra OUTRO serviço
    // Se cobrar() falhar, @Transactional NÃO desfaz o reservar() que já rodou
    // em outro serviço, com seu próprio banco — @Transactional só enxerga
    // a transação LOCAL deste serviço, nunca atravessa a rede.
}
